module shift_register (
    input clk,
    input rst_n,
    input load,
    input [15:0] parallel_in,
    input serial_in,
    output serial_out
);

    reg [15:0] data_reg;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            data_reg <= 16'b0;
        else if (load)
            data_reg <= parallel_in;
        else
            data_reg <= {serial_in, data_reg[15:1]};
    end

    assign serial_out = data_reg[0];

endmodule
